    15→    return () => window.removeEventListener("scroll", handleScroll);
    16→  }, []);
    17→
    18→  const scrollToSection = (sectionId: string) => {
    19→    const element = document.getElementById(sectionId);
    20→    if (element) {
    21→      element.scrollIntoView({ behavior: "smooth" });
