    46→            whileHover={{ scale: 1.05 }}
    47→            className="flex items-center cursor-pointer"
    48→            onClick={() => scrollToSection("home")}
    49→          >
    50→            <h1 className="text-2xl font-space font-bold gradient-text">
    51→              WebAksh
    52→            </h1>
    53→          </motion.div>
    54→          
    55→          <div className="hidden md:flex items-center space-x-8">
    56→            {navItems.map((item) => (
    57→              <motion.button
    58→                key={item.href}
